(function ($) {
    'use strict';
  
    $(document).ready(function () {
      const urlParams = new URLSearchParams(window.location.search);
      const searchQuery = urlParams.get('q');
      const $resultsContainer = $('#search-results');
      const $loading = $('#search-loading');
      const $title = $('#search-title');
  
      // Ensure we use the correct index path generated by Docsy
      const searchIndexUrl = "/offline-search-index.json"; 

      if (!searchQuery) {
        $loading.hide();
        $resultsContainer.html('<p>Please enter a search term.</p>');
        return;
      }
  
      $title.text(`Showing results for "${searchQuery}"`);
  
      $.ajax(searchIndexUrl).then((data) => {
        
        // 1. Initialize Search Engine
        const idx = lunr(function () {
          this.ref('ref');
          this.field('title', { boost: 100 });
          this.field('description', { boost: 50 });
          this.field('body');
          data.forEach((doc) => { this.add(doc); });
        });
  
        // 2. Run Search (Fuzzy matching)
        const results = idx.search(`${searchQuery} ${searchQuery}*`);
        $loading.hide();
  
        if (results.length === 0) {
          $resultsContainer.html('<p>No results found.</p>');
          return;
        }
  
        const $list = $('<div class="search-results-list" style="padding-left: 10px;">');
        
        results.forEach((r) => {
          const doc = data.find(d => d.ref === r.ref);
          
          // Filter out release notes to keep documentation clean
          if (doc.ref.includes("/project/releases/")) return;

          // Snippet generation logic
          let snippet = doc.description;
          if (!snippet || snippet.length < 10) {
              snippet = doc.body.substring(0, 300);
          }
          if (snippet.length > 300) {
              snippet = snippet.substring(0, 300) + "...";
          }

          // HIGHLIGHTING LOGIC
          const regex = new RegExp(`(${searchQuery})`, "gi");
          
          // Apply green highlight ONLY to titles
          const highlightedTitle = doc.title.replace(regex, "<span style='color:#00b39f; font-weight:bold;'>$1</span>");
          
          // NO HIGHLIGHTING for snippets (keeps paragraph text plain grey)
          const cleanSnippet = snippet;

          // 3. Render the Result Item
          const item = `
            <div class="search-result-item" style="margin-bottom: 2rem;">
              <h3 style="margin-bottom: 0.5rem; font-size: 1.3rem; line-height: 1.4;">
                  <span style="color: #00b39f; margin-right: 8px;">&bull;</span>
                  <a href="${doc.ref}" style="color: #00b39f; text-decoration: none; font-weight: 500;">
                    ${highlightedTitle}
                  </a>
              </h3>
              
              <p style="color: #ccc; font-size: 1rem; line-height: 1.6; padding-left: 20px;">
                ${cleanSnippet}
              </p>
            </div>
          `;
          $list.append(item);
        });
  
        $resultsContainer.append($list);

      }).catch((err) => {
          console.error("Error loading search index:", err);
          $loading.hide();
          $resultsContainer.html('<p>Error loading search index.</p>');
      });
    });
  })(jQuery);